### Option 2: Python (Blender API)
If you prefer a Python script to generate a model file that you can open in Blender, here is a script using the `bpy` module:

```python
import bpy
import math

# Clear existing objects
for obj in bpy.data.objects:
    bpy.data.objects.remove(obj, do_unlink=True)

# Create a simple house
# 1. Floor
bpy.ops.mesh.primitive_cube_add(size=10, location=(0, 0, -0.5))
floor = bpy.context.active_object
floor.name = "Floor"
floor.scale = (10, 1, 10)
floor.data.materials.append(bpy.data.materials.new(name="Grass"))
floor.data.materials[0].diffuse_color = (0.2, 0.8, 0.2)

# 2. Walls
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 3, 0))
wall = bpy.context.active_object
wall.name = "Walls"
wall.scale = (8, 6, 8)
wall.data.materials.append(bpy.data.materials.new(name="Wall"))
wall.data.materials[0].diffuse_color = (0.9, 0.9, 0.9)

# 3. Roof
bpy.ops.mesh.primitive_cone_add(radius1=7, depth=4, location=(0, 8, 0), vertices=4)
roof = bpy.context.active_object
roof.name = "Roof"
roof.rotation_euler = (0, math.pi/4, 0)
roof.data.materials.append(bpy.data.materials.new(name="Roof"))
roof.data.materials[0].diffuse_color = (0.5, 0.3, 0.1)

# 4. Door
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 2, 4.1))
door = bpy.context.active_object
door.name = "Door"
door.scale = (2, 4, 0.2)
door.data.materials.append(bpy.data.materials.new(name="Door"))
door.data.materials[0].diffuse_color = (0.3, 0.2, 0.1)

# Export to OBJ
bpy.ops.export_scene.obj(filepath="house_model.obj", global_scale=1.0, use_selection=False)
